class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string result = "";
        for (int i = 0; i < s.length(); i++) {
            if (s[i] != '-') {
                result += toupper(s[i]);
            }
        }
        int count = 0;
        for (int i = result.length() - 1; i >= 0; i--) {
            result[i] = result[i];
            count++;
            if (count == k) {
                result.insert(i, "-");
                count = 0;
            }
        }
        return result.substr(0, result.length() - 1);
    }
};
```
